## Domain Layer Implementation

### Entity Design

Entities are domain objects with unique identifiers. While attributes change over time, the identity remains constant.

```
// User entity
import { UserId } from './value-objects/UserId';
import { Email } from './value-objects/Email';

export class User {
  private userId: UserId;
  private email: Email;
  private name: string;
  private age: number;
  private createdAt: Date;
  private updatedAt: Date;

  constructor(
    userId: UserId,
    email: Email,
    name: string,
    age: number,
    createdAt: Date = new Date(),
    updatedAt: Date = new Date()
  ) {
    this.validate(name, age);
    this.userId = userId;
    this.email = email;
    this.name = name;
    this.age = age;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
  }

  private validate(name: string, age: number): void {
    if (!name || name.trim().length === 0) {
      throw new Error('User name must not be empty');
    }
    if (age < 0 || age > 150) {
      throw new Error('User age must be between 0 and 150');
    }
  }

  // Business logic: age validation
  isAdult(): boolean {
    return this.age >= 18;
  }

  // Business logic: update email
  changeEmail(newEmail: Email): void {
    this.email = newEmail;
    this.updatedAt = new Date();
  }

  // Business logic: update profile
  updateProfile(name: string, age: number): void {
    this.validate(name, age);
    this.name = name;
    this.age = age;
    this.updatedAt = new Date();
  }

  // Getters
  getId(): UserId {
    return this.userId;
  }

  getEmail(): Email {
    return this.email;
  }

  getName(): string {
    return this.name;
  }

  getAge(): number {
    return this.age;
  }

