## Testing - Where Clean Architecture Really Pays Off

Here is where this whole exercise pays dividends. Because your business logic has zero infrastructure dependencies, you can test it with fast, reliable unit tests.

```
csharpusing CleanArch.Domain.Entities;

namespace CleanArch.Tests.Domain;

public class ProductTests
{
    [Fact]
    public void Constructor_WithValidData_CreatesProduct()
    {
        var product = new Product("Laptop", "A good laptop", 999.99m, 50);

        Assert.Equal("Laptop", product.Name);
        Assert.Equal(999.99m, product.Price);
        Assert.Equal(50, product.StockQuantity);
    }

    [Fact]
    public void Constructor_WithNegativePrice_ThrowsException()
    {
        Assert.Throws<ArgumentException>(() =>
            new Product("Laptop", "A good laptop", -100m, 50));
    }

    [Fact]
    public void ReduceStock_WithInsufficientQuantity_ThrowsException()
    {
        var product = new Product("Mouse", "Wireless mouse", 25m, 5);

        Assert.Throws<InvalidOperationException>(() =>
            product.ReduceStock(10));
    }

    [Fact]
    public void ReduceStock_WithValidQuantity_UpdatesStock()
    {
        var product = new Product("Keyboard", "Mechanical keyboard", 75m, 20);

        product.ReduceStock(5);

        Assert.Equal(15, product.StockQuantity);
    }
}

```

And for the Application layer, you can mock the repository:

```
csharpusing CleanArch.Application.DTOs;
using CleanArch.Application.Interfaces;
using CleanArch.Application.Services;
using CleanArch.Domain.Entities;
using Moq;

namespace CleanArch.Tests.Application;

public class ProductServiceTests
{
    private readonly Mock<IProductRepository> _repoMock;
    private readonly Mock<IUnitOfWork> _uowMock;
    private readonly ProductService _service;

    public ProductServiceTests()
    {
        _repoMock = new Mock<IProductRepository>();
        _uowMock = new Mock<IUnitOfWork>();
        _service = new ProductService(_repoMock.Object, _uowMock.Object);
    }

    [Fact]
    public async Task CreateProductAsync_ReturnsCreatedProduct()
    {
        var request = new CreateProductRequest("Laptop", "Gaming laptop", 1500m, 10);

        _uowMock.Setup(u => u.SaveChangesAsync(It.IsAny<CancellationToken>()))
                 .ReturnsAsync(1);

        var result = await _service.CreateProductAsync(request);

        Assert.Equal("Laptop", result.Name);
        Assert.Equal(1500m, result.Price);
        _repoMock.Verify(r => r.AddAsync(It.IsAny<Product>(), It.IsAny<CancellationToken>()), Times.Once);
        _uowMock.Verify(u => u.SaveChangesAsync(It.IsAny<CancellationToken>()), Times.Once);
    }

    [Fact]
    public async Task GetProductByIdAsync_WhenNotFound_ReturnsNull()
    {
        _repoMock.Setup(r => r.GetByIdAsync(It.IsAny<Guid>(), It.IsAny<CancellationToken>()))
                  .ReturnsAsync((Product?)null);

        var result = await _service.GetProductByIdAsync(Guid.NewGuid());

        Assert.Null(result);
    }
}

```

No database. No HTTP. No Docker container spinning up. Just fast, deterministic tests that give you confidence your logic is correct.

